// SetDataSource of the crawlTarget to the related item.
// Sets o.R.DataSource to related.
// Adds o to related.R.CrawlTargets.
func (o *CrawlTarget) SetDataSource(ctx context.Context, exec boil.ContextExecutor, insert bool, related *DataSource) error {
	var err error
	if insert {
		if err = related.Insert(ctx, exec, boil.Infer()); err != nil {
			return errors.Wrap(err, "failed to insert into foreign table")
		}
	}

	updateQuery := fmt.Sprintf(
		"UPDATE \"ingest\".\"crawl_targets\" SET %s WHERE %s",
		strmangle.SetParamNames("\"", "\"", 1, []string{"data_source_id"}),
		strmangle.WhereClause("\"", "\"", 2, crawlTargetPrimaryKeyColumns),
	)
	values := []any{related.ID, o.ID}

	if boil.IsDebug(ctx) {
		writer := boil.DebugWriterFrom(ctx)
		fmt.Fprintln(writer, updateQuery)
		fmt.Fprintln(writer, values)
	}
	if _, err = exec.ExecContext(ctx, updateQuery, values...); err != nil {
		return errors.Wrap(err, "failed to update local table")
	}

	o.DataSourceID = related.ID
	if o.R == nil {
		o.R = &crawlTargetR{
			DataSource: related,
		}
	} else {
		o.R.DataSource = related
	}

	if related.R == nil {
		related.R = &dataSourceR{
			CrawlTargets: CrawlTargetSlice{o},
		}
	} else {
		related.R.CrawlTargets = append(related.R.CrawlTargets, o)
	}

	return nil
}

