// SetTargetDryrunResults removes all previously related items of the
// crawl_target replacing them completely with the passed
// in related items, optionally inserting them as new records.
// Sets o.R.Target's TargetDryrunResults accordingly.
// Replaces o.R.TargetDryrunResults with related.
// Sets related.R.Target's TargetDryrunResults accordingly.
func (o *CrawlTarget) SetTargetDryrunResults(ctx context.Context, exec boil.ContextExecutor, insert bool, related ...*DryrunResult) error {
	query := "update \"ingest\".\"dryrun_results\" set \"target_id\" = null where \"target_id\" = $1"
	values := []any{o.ID}
	if boil.IsDebug(ctx) {
		writer := boil.DebugWriterFrom(ctx)
		fmt.Fprintln(writer, query)
		fmt.Fprintln(writer, values)
	}
	_, err := exec.ExecContext(ctx, query, values...)
	if err != nil {
		return errors.Wrap(err, "failed to remove relationships before set")
	}

	if o.R != nil {
		for _, rel := range o.R.TargetDryrunResults {
			queries.SetScanner(&rel.TargetID, nil)
			if rel.R == nil {
				continue
			}

			rel.R.Target = nil
		}
		o.R.TargetDryrunResults = nil
	}

	return o.AddTargetDryrunResults(ctx, exec, insert, related...)
}

// RemoveTargetDryrunResults relationships from objects passed in.
// Removes related items from R.TargetDryrunResults (uses pointer comparison, removal does not keep order)
// Sets related.R.Target.
func (o *CrawlTarget) RemoveTargetDryrunResults(ctx context.Context, exec boil.ContextExecutor, related ...*DryrunResult) error {
	if len(related) == 0 {
		return nil
	}

	var err error
	for _, rel := range related {
		queries.SetScanner(&rel.TargetID, nil)
		if rel.R != nil {
			rel.R.Target = nil
		}
		if _, err = rel.Update(ctx, exec, boil.Whitelist("target_id")); err != nil {
			return err
		}
	}
	if o.R == nil {
		return nil
	}

	for _, rel := range related {
		for i, ri := range o.R.TargetDryrunResults {
			if rel != ri {
				continue
			}

			ln := len(o.R.TargetDryrunResults)
			if ln > 1 && i < ln-1 {
				o.R.TargetDryrunResults[i] = o.R.TargetDryrunResults[ln-1]
			}
			o.R.TargetDryrunResults = o.R.TargetDryrunResults[:ln-1]
			break
		}
	}

	return nil
}

